import novamind_api as nm

# Check social posts
posts = nm.analytics.get_social_posts(days=14, limit=50)
if isinstance(posts, dict) and 'rows' in posts:
    for p in posts['rows'][:10]:
        print(p)
elif isinstance(posts, list):
    for p in posts[:10]:
        if isinstance(p, dict):
            print({k: v for k, v in p.items() if k != 'content'})
        else:
            print(p)
else:
    print(f"Type: {type(posts)}")
    print(posts[:500] if isinstance(posts, str) else posts)
